import sys
from functools import lru_cache

class Solution:
    def countPartitions(self, nums, k):
        MOD = 10**9 + 7
        n = len(nums)
        sys.setrecursionlimit(100000)

        @lru_cache(maxsize=None)
        def go(i):
            if i == n:
                return 1
            tot = 0
            mn = mx = nums[i]
            for j in range(i, n):
                if nums[j] < mn:
                    mn = nums[j]
                if nums[j] > mx:
                    mx = nums[j]
                if mx - mn <= k:
                    tot = (tot + go(j + 1)) % MOD
            return tot

        res = go(0)
        go.cache_clear()
        return res

