var countPartitions = function(nums, k) {
    const MOD = 1000000007n;
    const n = nums.length;
    const dp = new Array(n + 1).fill(0n);
    dp[0] = 1n;
    const pref = new Array(n + 2).fill(0n);
    pref[1] = 1n;
    let left = 0;
    const maxq = [];
    const minq = [];
    for (let i = 1; i <= n; i++) {
        const v = nums[i - 1];
        while (maxq.length && nums[maxq[maxq.length - 1]] <= v) maxq.pop();
        maxq.push(i - 1);
        while (minq.length && nums[minq[minq.length - 1]] >= v) minq.pop();
        minq.push(i - 1);
        while (nums[maxq[0]] - nums[minq[0]] > k) {
            left++;
            if (maxq[0] < left) maxq.shift();
            if (minq[0] < left) minq.shift();
        }
        let val = (pref[i] - pref[left]) % MOD;
        if (val < 0n) val += MOD;
        dp[i] = val;
        pref[i + 1] = (pref[i] + dp[i]) % MOD;
    }
    return Number(dp[n] % MOD);
};
